{
  "query": "query AdminListUsers($page: Int, $pageSize: Int) {
  adminUsers(page: $page, pageSize: $pageSize) {
    users {
      id
      email
      displayName
      role
      status
      createdAt
    }
    totalCount
    page
    pageSize
  }
}",
  "variables": {
    "page": 1,
    "pageSize": 10
  }
}

